<template><section class="quick-replies-page"><header><button @click="$emit('close')"><ArrowLeft/></button><strong>快捷短语</strong><span/><button @click="picker?.click()">导入</button><button @click="exportReplies">导出</button></header><div class="quick-search"><Search/><input v-model="keyword" placeholder="搜索快捷短语" @input="load"></div><div class="quick-toolbar"><button class="primary" @click="begin()"><Plus/>新增短语</button><span>{{replies.length}} 条</span></div><p v-if="notice" class="quick-notice">{{notice}}</p><div class="quick-list"><article v-for="q in replies" :key="q.id" @click="$emit('select',q.content)"><p>{{q.content}}</p><div><button @click.stop="begin(q)"><Pencil/></button><button class="danger" @click.stop="remove(q.id)"><Trash2/></button></div></article><p v-if="!replies.length" class="empty">没有匹配的快捷短语</p></div><div v-if="editing" class="quick-editor-mask"><form class="quick-editor" @submit.prevent="save"><h3>{{editing.id?'编辑短语':'新增短语'}}</h3><textarea v-model="editing.content" rows="6" placeholder="短语内容" autofocus/><p v-if="editError" class="error">{{editError}}</p><footer><button type="button" @click="editing=null">取消</button><button class="primary">保存</button></footer></form></div><input ref="picker" hidden type="file" accept="application/json,.json" @change="importReplies"></section></template>
<script setup lang="ts">import{onMounted,ref}from'vue';import{ArrowLeft,Search,Plus,Pencil,Trash2}from'lucide-vue-next';defineEmits(['close','select']);const replies=ref<any[]>([]),keyword=ref(''),editing=ref<any>(null),editError=ref(''),notice=ref(''),picker=ref<HTMLInputElement>();async function api(url:string,options?:RequestInit){const r=await fetch(url,options),j=await r.json().catch(()=>({}));if(!r.ok)throw Error(j.message||'操作失败');return j}async function load(){try{replies.value=(await api('/api/koshop-seller/quick-replies?keyword='+encodeURIComponent(keyword.value.trim()))).items||[]}catch(e:any){notice.value=e.message}}function begin(q?:any){editError.value='';editing.value={id:q?.id,content:q?.content||''}}async function save(){const content=editing.value.content.trim();if(!content)return editError.value='短语内容不能为空';try{await api('/api/koshop-seller/quick-replies'+(editing.value.id?'/'+editing.value.id:''),{method:editing.value.id?'PUT':'POST',headers:{'content-type':'application/json'},body:JSON.stringify({content})});editing.value=null;await load()}catch(e:any){editError.value=e.message}}async function remove(id:string){if(!confirm('确定删除这条快捷短语吗？'))return;try{await api('/api/koshop-seller/quick-replies/'+id,{method:'DELETE'});await load()}catch(e:any){notice.value=e.message}}async function importReplies(e:Event){const el=e.target as HTMLInputElement,file=el.files?.[0];if(!file)return;try{const items=JSON.parse(await file.text());await api('/api/koshop-seller/quick-replies/import',{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({items})});notice.value='导入成功';await load()}catch(e:any){notice.value='导入失败：'+(e.message||'文件格式错误')}finally{el.value=''}}async function exportReplies(){try{const r=await fetch('/api/koshop-seller/quick-replies/export');if(!r.ok)throw Error('导出失败');const a=document.createElement('a');a.href=URL.createObjectURL(await r.blob());a.download='koshop-quick-replies.json';a.click();URL.revokeObjectURL(a.href)}catch(e:any){notice.value=e.message}}onMounted(load)</script>
